"use strict";(self.webpackChunk_N_E=self.webpackChunk_N_E||[]).push([[768],{94768:function(e,t,s){s.d(t,{I18nProvider:function(){return o},Q:function(){return d}});var a=s(57437),r=s(2265);let i={ja:{"app.name":"StudyLink","app.tagline":"先生の時間を、生徒のために。","app.companyContext":"学習塾・スクール向け","app.footer":"StudyLink - Product Demo. 本デモのデータはすべて架空のものです。","nav.dashboard":"ダッシュボード","nav.students":"生徒管理","nav.schedule":"授業・時間割","nav.tutor":"AIチューター","nav.grading":"AI自動採点","nav.reports":"保護者レポート","nav.risk":"つまずき検知・退塾リスク","nav.materials":"AI小テスト・教材生成","header.language":"言語","header.japanese":"日本語","header.english":"EN","header.avatar":"教室長","header.menu":"メニュー","common.ai":"AI","common.close":"閉じる","common.details":"詳細","common.students":"生徒","common.score":"得点","common.attendance":"出席率","common.course":"コース","common.level":"レベル","common.room":"教室","common.teacher":"担当講師","common.count":"名","common.processing":"処理中...","common.image":"イメージ","course.eikaiwa1":"英会話初級","course.eikaiwa2":"英会話中級","course.math":"数学","course.kokugo":"国語","course.toeic":"TOEIC対策","day.mon":"月","day.tue":"火","day.wed":"水","day.thu":"木","day.fri":"金","day.sat":"土","dashboard.title":"ダッシュボード","dashboard.subtitle":"教室全体の状況とAIからの気づきを確認します。","dashboard.enrolledKpi":"在籍生徒数","dashboard.todayClassesKpi":"本日の授業","dashboard.attendanceKpi":"出席率（今月）","dashboard.homeworkKpi":"未提出課題","dashboard.attendanceTrend":"出席率の推移（12週間）","dashboard.studentsByCourse":"コース別の生徒数","dashboard.aiInsights":"AIからの気づき","dashboard.insight1":"英会話初級クラスの出席率が3週連続で低下しています。木曜17:30の枠は部活動と重なる生徒が多く、振替枠の案内を推奨します。","dashboard.insight2":"数学（中3）の直近テスト平均は78点で、前回から6点改善しました。二次関数の単元で伸びた生徒が多く見られます。","dashboard.insight3":"未提出課題17件のうち9件がTOEIC対策コースに集中しています。リマインド配信のテンプレートを用意すると回収率が上がる見込みです。","dashboard.attendanceUnit":"出席率（%）","dashboard.studentUnit":"生徒数","dashboard.classesToday":"本日 5コマ","students.title":"生徒管理","students.subtitle":"在籍40名の生徒を一覧で確認し、行をクリックすると個人の学習状況を表示します。","students.searchPlaceholder":"生徒名で検索...","students.filterCourse":"コースで絞り込み","students.filterAll":"すべて","students.table.name":"生徒名","students.table.course":"コース","students.table.level":"レベル","students.table.score":"直近の得点","students.table.attendance":"出席率","students.drawer.title":"生徒詳細","students.drawer.profile":"プロフィール","students.drawer.progress":"成績の推移（直近5回）","students.drawer.progressHint":"テスト得点の推移です。実装版では課題提出や理解度も重ねて表示できます。","students.drawer.attendanceLabel":"今学期の出席率","students.drawer.homeworkLabel":"課題提出","students.drawer.homeworkValue":"提出済み","students.empty":"該当する生徒がいません。","students.testLabel":"第","students.testUnit":"回","schedule.title":"授業・時間割","schedule.subtitle":"今週の時間割です。コマをクリックすると担当講師と受講人数を確認できます。","schedule.weekLabel":"2026年7月13日の週","schedule.detailTitle":"授業の詳細","schedule.enrolled":"受講人数","schedule.capacity":"定員","schedule.timeLabel":"時間","schedule.emptySlot":"－","schedule.selectHint":"コマをクリックすると詳細が表示されます。","schedule.summary":"今週の授業数","schedule.summaryUnit":"コマ","schedule.imageAlt":"授業風景のイメージ","schedule.detailHint":"講師・受講人数・教室を確認できます。","tutor.title":"AIチューター","tutor.subtitle":"生徒の質問にAIが段階的に答えるデモです。質問チップを選ぶか、自由に入力してください。","tutor.badgeLabel":"学習支援AI","tutor.welcome":"こんにちは！わからないところを一緒に解決しましょう。下の質問例から選んでもいいですよ。","tutor.inputPlaceholder":"質問を入力...","tutor.send":"送信","tutor.thinking":"AIチューターが考えています...","tutor.chip.grammar":"この英文法がわかりません（現在完了）","tutor.chip.math":"数学の二次関数を説明して","tutor.chip.essay":"英作文を直して","tutor.answer.grammar":"いい質問ですね！現在完了は「過去の出来事が今につながっている」ときに使います。ステップで見てみましょう。 1) 形は have/has + 過去分詞。 2) 「経験」: I have visited Kyoto.（京都に行ったことがある） 3) 「継続」: I have lived here for two years.（2年間ずっと住んでいる） 4) 「完了」: I have just finished my homework.（ちょうど終えたところ） yesterday や last year など「過去の一点」を表す言葉とは一緒に使えない点に注意しましょう。この調子です！","tutor.answer.math":"二次関数、いっしょに整理しましょう！ 1) 基本の形は y = ax\xb2 + bx + c。グラフは放物線になります。 2) a が正なら上に開き、負なら下に開きます。 3) 頂点は平方完成で求められます: y = a(x-p)\xb2 + q なら頂点は (p, q)。 4) 例: y = x\xb2 - 4x + 3 は y = (x-2)\xb2 - 1 になるので、頂点は (2, -1)、x軸との交点は x = 1 と x = 3 です。まずは平方完成の練習問題を3問解いてみましょう。できたら次に進みますよ！","tutor.answer.essay":"英作文の添削ですね！下の「英作文チェック」に文章を入れると、直すところを色付きで示します。サンプルの文章もセットしてあるので、「AIで添削する」ボタンを押してみてください。間違いは赤、直した表現は緑で表示されます。","tutor.answer.default":"ごめんなさい、その質問はデモ版では用意していません。実装版では教材と生徒の学習履歴をもとに、どの単元の質問にも答えられます。","tutor.essayTitle":"英作文チェック","tutor.essayHelp":"サンプルの英作文をAIが添削します。赤=誤り、緑=修正後の表現です。","tutor.essayButton":"AIで添削する","tutor.essayChecking":"AIが添削しています...","tutor.essayResultTitle":"添削結果","tutor.essayLegendDel":"誤り","tutor.essayLegendIns":"修正","tutor.essayExplanationTitle":"解説","tutor.essayExplanation1":"「last summer」は過去の一点を表すので、現在完了ではなく過去形 went を使います。","tutor.essayExplanation2":"enjoy は動名詞をとる動詞です。enjoy seeing が正しく、temple は数えられる名詞なので many temples とします。","tutor.essayExplanation3":"if節の中では未来のことでも現在形を使います。If I have time が自然です。","tutor.essayEncourage":"文章の流れはとても良いです。時制に気をつければ、さらに伝わる英文になりますよ！","grading.title":"AI自動採点","grading.subtitle":"答案の種類を選んで採点を実行すると、AIが得点・主な誤り・コメントを生成します。","grading.selectTest":"採点する答案を選択","grading.test.essay":"英作文","grading.test.reading":"読解","grading.test.choice":"選択式","grading.run":"AI採点を実行","grading.running":"AIが採点しています...","grading.resultTitle":"採点結果","grading.table.student":"生徒名","grading.table.score":"得点","grading.table.issue":"主な誤り","grading.table.comment":"AIコメント","grading.timeSavedTitle":"採点時間の削減","grading.timeBefore":"手作業","grading.timeBeforeValue":"3時間","grading.timeAfter":"AI採点","grading.timeAfterValue":"4分","grading.timeNote":"採点後は先生が確認・調整するだけ。空いた時間を生徒指導にあてられます。","grading.empty":"答案を選んで「AI採点を実行」を押してください。","grading.average":"平均点","grading.graded":"採点済み","reports.title":"保護者レポート","reports.subtitle":"生徒を選ぶと、AIが今月の学習レポートを自動生成します。","reports.selectStudent":"生徒を選択","reports.generate":"AIで月次レポートを生成","reports.generating":"AIがレポートを作成しています...","reports.previewTitle":"レポートプレビュー","reports.monthLabel":"2026年7月 月次レポート","reports.sectionProgress":"今月の学習状況","reports.sectionStrengths":"良かった点","reports.sectionFocus":"これからの課題","reports.sectionNext":"来月のご提案","reports.send":"保護者に送信","reports.sentToast":"レポートを送信しました（デモ）","reports.empty":"生徒を選択して「AIで月次レポートを生成」を押してください。","reports.greeting":"保護者様","reports.closing":"ご不明な点があれば、いつでも教室までご連絡ください。","reports.r1.progress":"美咲さんは今月、英会話初級クラスに8回出席しました（出席率100%）。直近のスピーキングテストは82点で、前回から7点アップしています。","reports.r1.strengths":"あいさつや自己紹介の定型表現がスムーズに出るようになり、授業内の発話回数もクラス平均を上回っています。宿題の提出も毎回期限内でした。","reports.r1.focus":"過去形の文で動詞の変化に迷う場面がありました。日記形式の短い英作文で、過去形に慣れる練習を進めます。","reports.r1.next":"来月は「過去のできごとを話す」単元に入ります。ご家庭でも週末の出来事を英語で一言話す習慣づけをおすすめします。","reports.r2.progress":"蓮さんは今月、数学クラスに7回出席しました（出席率88%）。単元テスト「二次関数」は74点で、クラス平均の71点を上回りました。","reports.r2.strengths":"平方完成の手順が安定し、計算ミスが前月の半分以下に減りました。授業中の質問も増え、理解を確かめながら進められています。","reports.r2.focus":"文章題からグラフを描く問題で手が止まる傾向があります。図を描いて整理する練習を宿題に組み込みます。","reports.r2.next":"来月は入試頻出の「関数と図形の融合問題」に取り組みます。1日2問の演習ペースを目標にします。","reports.r3.progress":"杏さんは今月、TOEIC対策クラスに8回出席しました（出席率100%）。模試スコアは615点で、目標の600点を初めて超えました。","reports.r3.strengths":"Part 5（文法）の正答率が78%まで伸び、語彙の学習アプリも毎日継続できています。リスニングの先読みも習慣化しました。","reports.r3.focus":"Part 7の長文で時間が不足しがちです。設問先読みと段落ごとの要点把握で、読むスピードを上げていきます。","reports.r3.next":"来月は本番形式の模試を2回実施し、730点コースへのステップアップを判断します。","dashboard.heroAlt":"学習教室のイメージ","dashboard.testimonialsTitle":"お客様の声","dashboard.testimonialsSubtitle":"教育現場での使いやすさをイメージしたサンプルコメントです。","dashboard.sampleImages":"※イメージ（サンプル）","dashboard.testimonialAlt":"人物イメージ","dashboard.testimonial1Name":"佐々木 真帆","dashboard.testimonial1Company":"みらい学習室（架空）","dashboard.testimonial1Quote":"日々の確認が一画面にまとまり、生徒と話す時間をつくりやすくなりました。","dashboard.testimonial2Name":"中村 亮","dashboard.testimonial2Company":"青空アカデミー（架空）","dashboard.testimonial2Quote":"クラスの様子をすぐ共有でき、保護者への案内も準備しやすくなりました。","reports.historyTitle":"月次レポート履歴","reports.historyReady":"作成済み","reports.history1":"英会話初級：会話練習と宿題の振り返り","reports.history2":"数学：二次関数の理解度を共有","reports.history3":"TOEIC対策：語彙と読解の進捗","reports.comparisonTitle":"前月との進捗比較","reports.comparisonApril":"4月","reports.comparisonMay":"5月","reports.comparisonJune":"6月","reports.comparisonNote":"直近3か月で理解度は安定して上向いています。次回は文章問題の練習量を増やす提案です。","risk.title":"つまずき検知・退塾リスク","risk.subtitle":"出席率と成績傾向をもとに、早めのフォローが必要な生徒をAIが見つけます。","risk.tableTitle":"生徒別リスク一覧","risk.student":"生徒名","risk.trend":"成績傾向","risk.risk":"退塾リスク（AI）","risk.reason":"主な理由","risk.down":"低下傾向","risk.stable":"安定・上向き","risk.level.high":"高","risk.level.medium":"中","risk.level.low":"低","risk.reasonHigh":"欠席が増え、直近の得点が低下","risk.reasonMedium":"課題の提出と出席にばらつき","risk.reasonLow":"出席・成績ともに安定","risk.heatmapTitle":"つまずき単元ヒートマップ","risk.heatmapHint":"赤い単元は、個別の声かけや復習教材を優先する目安です。","risk.unit1":"英会話","risk.unit2":"数学","risk.unit3":"国語","risk.unit4":"TOEIC","risk.unit5":"作文","risk.unit6":"文法","risk.unit7":"読解","risk.unit8":"関数","risk.unit9":"語彙","risk.unit10":"発音","risk.followTitle":"高リスク生徒へのフォロー","risk.highCount":"名が優先フォロー対象です。","risk.action":"フォロー策をAI提案","risk.running":"AIがフォロー策を作成中...","risk.result":"まずは今週中に短い面談を設定し、欠席理由と学習負荷を確認します。次に、基礎単元の10分復習と振替授業の候補を案内し、2週間後に出席・課題状況を再確認しましょう。","materials.title":"AI小テスト・教材生成","materials.subtitle":"科目と難易度を選ぶだけで、授業に使える小テストをAIが作成します。","materials.formTitle":"生成条件","materials.subject":"科目","materials.subjectEnglish":"英語","materials.subjectMath":"数学","materials.subjectJapanese":"国語","materials.unit":"単元","materials.unitValue":"現在完了","materials.difficulty":"難易度","materials.difficultyValue":"標準","materials.count":"問題数","materials.generate":"AIで生成","materials.running":"AIが教材を生成中...","materials.resultTitle":"生成された小テスト","materials.empty":"条件を選んで「AIで生成」を押してください。","materials.print":"印刷","materials.export":"エクスポート","materials.answer":"答え","materials.q1":"I ___ lived here for three years.（have / has）","materials.a1":"have","materials.e1":"I に合わせて have を使います。","materials.q2":"She has ___ her homework.（finish / finished）","materials.a2":"finished","materials.e2":"has の後は過去分詞です。","materials.q3":"Have you ever ___ sushi?（eat / eaten）","materials.a3":"eaten","materials.e3":"ever を使う経験の質問では過去分詞を使います。","materials.q4":"We have ___ seen that film.（already / yesterday）","materials.a4":"already","materials.e4":"yesterday は過去の一点なので現在完了とは使いません。","materials.q5":"Choose the correct sentence.","materials.a5":"He has just arrived.","materials.e5":"has + 過去分詞で「ちょうど到着した」を表します。"},en:{"app.name":"StudyLink","app.tagline":"Give teachers their time back - for students.","app.companyContext":"For cram schools and academies","app.footer":"StudyLink - Product Demo. All data is fictitious.","nav.dashboard":"Dashboard","nav.students":"Students","nav.schedule":"Schedule","nav.tutor":"AI Tutor","nav.grading":"Auto Grading","nav.reports":"Parent Reports","nav.risk":"Learning Risk","nav.materials":"AI Quiz Builder","header.language":"Language","header.japanese":"日本語","header.english":"EN","header.avatar":"School Manager","header.menu":"Menu","common.ai":"AI","common.close":"Close","common.details":"Details","common.students":"Students","common.score":"Score","common.attendance":"Attendance","common.course":"Course","common.level":"Level","common.room":"Room","common.teacher":"Teacher","common.count":"students","common.processing":"Processing...","common.image":"Image","course.eikaiwa1":"English Conversation (Beginner)","course.eikaiwa2":"English Conversation (Intermediate)","course.math":"Mathematics","course.kokugo":"Japanese","course.toeic":"TOEIC Prep","day.mon":"Mon","day.tue":"Tue","day.wed":"Wed","day.thu":"Thu","day.fri":"Fri","day.sat":"Sat","dashboard.title":"Dashboard","dashboard.subtitle":"Review school-wide status and AI-generated insights.","dashboard.enrolledKpi":"Enrolled students","dashboard.todayClassesKpi":"Classes today","dashboard.attendanceKpi":"Attendance (this month)","dashboard.homeworkKpi":"Unsubmitted homework","dashboard.attendanceTrend":"Attendance trend (12 weeks)","dashboard.studentsByCourse":"Students by course","dashboard.aiInsights":"Insights from AI","dashboard.insight1":"Attendance in the beginner conversation class has dropped for three straight weeks. Many students in the Thursday 17:30 slot have club-activity conflicts - consider offering a make-up slot.","dashboard.insight2":"The latest math (grade 9) test average is 78, up 6 points. Many students improved on the quadratic functions unit.","dashboard.insight3":"9 of the 17 unsubmitted assignments are concentrated in the TOEIC prep course. A reminder template should raise the submission rate.","dashboard.attendanceUnit":"Attendance (%)","dashboard.studentUnit":"Students","dashboard.classesToday":"5 sessions today","students.title":"Students","students.subtitle":"Browse all 40 enrolled students. Click a row to open the individual learning profile.","students.searchPlaceholder":"Search by name...","students.filterCourse":"Filter by course","students.filterAll":"All","students.table.name":"Name","students.table.course":"Course","students.table.level":"Level","students.table.score":"Latest score","students.table.attendance":"Attendance","students.drawer.title":"Student details","students.drawer.profile":"Profile","students.drawer.progress":"Score progress (last 5 tests)","students.drawer.progressHint":"Test score history. The production version can overlay homework and comprehension data.","students.drawer.attendanceLabel":"Attendance this term","students.drawer.homeworkLabel":"Homework","students.drawer.homeworkValue":"Submitted","students.empty":"No students match your filters.","students.testLabel":"Test","students.testUnit":"","schedule.title":"Schedule","schedule.subtitle":"This week's timetable. Click a session to see the teacher and enrollment.","schedule.weekLabel":"Week of July 13, 2026","schedule.detailTitle":"Session details","schedule.enrolled":"Enrolled","schedule.capacity":"Capacity","schedule.timeLabel":"Time","schedule.emptySlot":"-","schedule.selectHint":"Click a session to show its details.","schedule.summary":"Sessions this week","schedule.summaryUnit":"sessions","schedule.imageAlt":"Classroom scene image","schedule.detailHint":"Review the instructor, enrollment, and classroom details.","tutor.title":"AI Tutor","tutor.subtitle":"A demo of AI answering student questions step by step. Pick a suggestion chip or type freely.","tutor.badgeLabel":"Learning AI","tutor.welcome":"Hi! Let's work through anything you find difficult. Feel free to pick one of the sample questions below.","tutor.inputPlaceholder":"Type a question...","tutor.send":"Send","tutor.thinking":"The AI tutor is thinking...","tutor.chip.grammar":"I don't understand this grammar (present perfect)","tutor.chip.math":"Explain quadratic functions","tutor.chip.essay":"Correct my English essay","tutor.answer.grammar":"Great question! The present perfect connects a past event to the present. Let's go step by step. 1) The form is have/has + past participle. 2) Experience: I have visited Kyoto. 3) Continuation: I have lived here for two years. 4) Completion: I have just finished my homework. Remember: you cannot combine it with words that pin down a single past moment like yesterday or last year. You're doing great!","tutor.answer.math":"Let's sort out quadratic functions together! 1) The basic form is y = ax2 + bx + c, and the graph is a parabola. 2) If a is positive it opens upward; if negative, downward. 3) You find the vertex by completing the square: for y = a(x-p)2 + q the vertex is (p, q). 4) Example: y = x2 - 4x + 3 becomes y = (x-2)2 - 1, so the vertex is (2, -1) and it crosses the x-axis at x = 1 and x = 3. Try three practice problems on completing the square, then we'll move on!","tutor.answer.essay":'Happy to correct your essay! Paste it into the Essay Check panel below - a sample essay is already set. Press the "Check with AI" button: mistakes are shown in red and corrections in green.',"tutor.answer.default":"Sorry, that question is not scripted in this demo. The production version answers questions on any unit using your course materials and each student's learning history.","tutor.essayTitle":"Essay Check","tutor.essayHelp":"The AI corrects a sample essay. Red = mistake, green = corrected expression.","tutor.essayButton":"Check with AI","tutor.essayChecking":"The AI is reviewing the essay...","tutor.essayResultTitle":"Correction result","tutor.essayLegendDel":"Mistake","tutor.essayLegendIns":"Correction","tutor.essayExplanationTitle":"Explanation","tutor.essayExplanation1":'"Last summer" points to a single past moment, so use the simple past "went" instead of the present perfect.',"tutor.essayExplanation2":'"Enjoy" takes a gerund: "enjoy seeing" is correct, and "temple" is countable, so it becomes "many temples".',"tutor.essayExplanation3":'Inside an if-clause we use the present tense even for future meaning: "If I have time" is natural.',"tutor.essayEncourage":"The flow of your writing is very good. Watch your tenses and your English will be even clearer!","grading.title":"Auto Grading","grading.subtitle":"Choose a test type and run grading - the AI produces scores, main errors, and comments.","grading.selectTest":"Select a test to grade","grading.test.essay":"Essay","grading.test.reading":"Reading","grading.test.choice":"Multiple choice","grading.run":"Run AI grading","grading.running":"The AI is grading...","grading.resultTitle":"Grading results","grading.table.student":"Student","grading.table.score":"Score","grading.table.issue":"Main error","grading.table.comment":"AI comment","grading.timeSavedTitle":"Grading time saved","grading.timeBefore":"Manual","grading.timeBeforeValue":"3 hours","grading.timeAfter":"AI grading","grading.timeAfterValue":"4 min","grading.timeNote":"Teachers only review and adjust after grading - the time saved goes back to students.","grading.empty":'Select a test and press "Run AI grading".',"grading.average":"Average","grading.graded":"graded","reports.title":"Parent Reports","reports.subtitle":"Pick a student and the AI generates this month's learning report automatically.","reports.selectStudent":"Select a student","reports.generate":"Generate monthly report with AI","reports.generating":"The AI is writing the report...","reports.previewTitle":"Report preview","reports.monthLabel":"Monthly Report - July 2026","reports.sectionProgress":"This month's progress","reports.sectionStrengths":"What went well","reports.sectionFocus":"Areas to work on","reports.sectionNext":"Suggestions for next month","reports.send":"Send to parents","reports.sentToast":"Report sent (demo)","reports.empty":'Select a student and press "Generate monthly report with AI".',"reports.greeting":"Dear Parents,","reports.closing":"Please feel free to contact the school at any time with any questions.","reports.r1.progress":"Misaki attended the beginner conversation class 8 times this month (100% attendance). Her latest speaking test score is 82, up 7 points from last time.","reports.r1.strengths":"Set phrases for greetings and self-introduction now come out smoothly, and her speaking turns per lesson are above the class average. All homework was submitted on time.","reports.r1.focus":"She sometimes hesitates over verb changes in past-tense sentences. We will practice short diary-style writing to build familiarity with the past tense.","reports.r1.next":'Next month we start the "talking about past events" unit. At home, a one-sentence English recap of the weekend would be a great habit.',"reports.r2.progress":"Ren attended the math class 7 times this month (88% attendance). He scored 74 on the quadratic functions unit test, above the class average of 71.","reports.r2.strengths":"His completing-the-square procedure is now stable, and calculation mistakes fell to less than half of last month. He also asks more questions in class, confirming understanding as he goes.","reports.r2.focus":"He tends to pause on word problems that require drawing a graph. We will add diagram-first practice to his homework.","reports.r2.next":"Next month we tackle function-and-geometry problems that appear frequently in entrance exams, aiming for a pace of two exercises per day.","reports.r3.progress":"An attended the TOEIC prep class 8 times this month (100% attendance). Her practice test score is 615, clearing the 600 target for the first time.","reports.r3.strengths":"Her Part 5 (grammar) accuracy rose to 78%, and she has kept up daily vocabulary app study. Pre-reading listening questions has become a habit.","reports.r3.focus":"She tends to run out of time on Part 7 long passages. We will speed up reading through question pre-reading and paragraph-level summarizing.","reports.r3.next":"Next month we will run two full-length practice tests and decide on stepping up to the 730-point course.","dashboard.heroAlt":"Learning classroom image","dashboard.testimonialsTitle":"Voices from the classroom","dashboard.testimonialsSubtitle":"Sample comments illustrating day-to-day use in education settings.","dashboard.sampleImages":"Sample images. For demonstration only.","dashboard.testimonialAlt":"Person image","dashboard.testimonial1Name":"Maho Sasaki","dashboard.testimonial1Company":"Mirai Learning Room (fictional)","dashboard.testimonial1Quote":"The daily overview is in one place, which makes it easier to create time to speak with students.","dashboard.testimonial2Name":"Ryo Nakamura","dashboard.testimonial2Company":"Blue Sky Academy (fictional)","dashboard.testimonial2Quote":"We can share how classes are going quickly and prepare parent communications with more confidence.","reports.historyTitle":"Monthly report history","reports.historyReady":"Ready","reports.history1":"Beginner conversation: speaking practice and homework review","reports.history2":"Math: shared progress on quadratic functions","reports.history3":"TOEIC prep: vocabulary and reading progress","reports.comparisonTitle":"Progress compared with prior months","reports.comparisonApril":"April","reports.comparisonMay":"May","reports.comparisonJune":"June","reports.comparisonNote":"Understanding has moved steadily upward over the past three months. The next recommendation is to add more word-problem practice.","risk.title":"Learning Friction & Retention Risk","risk.subtitle":"AI uses attendance and score patterns to spot students who may benefit from an earlier follow-up.","risk.tableTitle":"Student risk overview","risk.student":"Student","risk.trend":"Score trend","risk.risk":"Retention risk (AI)","risk.reason":"Primary reason","risk.down":"Declining","risk.stable":"Stable / improving","risk.level.high":"High","risk.level.medium":"Medium","risk.level.low":"Low","risk.reasonHigh":"More absences and falling recent scores","risk.reasonMedium":"Inconsistent homework or attendance","risk.reasonLow":"Attendance and achievement are steady","risk.heatmapTitle":"Learning-friction heatmap","risk.heatmapHint":"Red units are cues to prioritize an individual check-in or review material.","risk.unit1":"Conversation","risk.unit2":"Math","risk.unit3":"Japanese","risk.unit4":"TOEIC","risk.unit5":"Writing","risk.unit6":"Grammar","risk.unit7":"Reading","risk.unit8":"Functions","risk.unit9":"Vocabulary","risk.unit10":"Pronunciation","risk.followTitle":"Follow-up for high-risk students","risk.highCount":"students are prioritized for follow-up.","risk.action":"Get AI follow-up plan","risk.running":"AI is preparing the follow-up plan...","risk.result":"First, schedule a brief check-in this week to understand absences and workload. Then offer a 10-minute basics review and make-up class options, followed by an attendance and homework check in two weeks.","materials.title":"AI Quiz & Material Builder","materials.subtitle":"Choose a subject and difficulty, and AI creates a ready-to-use quiz for the lesson.","materials.formTitle":"Generation settings","materials.subject":"Subject","materials.subjectEnglish":"English","materials.subjectMath":"Math","materials.subjectJapanese":"Japanese","materials.unit":"Unit","materials.unitValue":"Present perfect","materials.difficulty":"Difficulty","materials.difficultyValue":"Standard","materials.count":"Questions","materials.generate":"Generate with AI","materials.running":"AI is generating materials...","materials.resultTitle":"Generated quiz","materials.empty":'Choose the settings and press "Generate with AI".',"materials.print":"Print","materials.export":"Export","materials.answer":"Answer","materials.q1":"I ___ lived here for three years. (have / has)","materials.a1":"have","materials.e1":"Use have with I.","materials.q2":"She has ___ her homework. (finish / finished)","materials.a2":"finished","materials.e2":"Use a past participle after has.","materials.q3":"Have you ever ___ sushi? (eat / eaten)","materials.a3":"eaten","materials.e3":"Experience questions with ever use a past participle.","materials.q4":"We have ___ seen that film. (already / yesterday)","materials.a4":"already","materials.e4":"Yesterday identifies a past point and does not pair with the present perfect.","materials.q5":"Choose the correct sentence.","materials.a5":"He has just arrived.","materials.e5":"Has + past participle expresses a very recent action."}},n=r.createContext(null);function o(e){let{children:t}=e,[s,o]=r.useState("ja");r.useEffect(()=>{let e=new URLSearchParams(window.location.search).get("lang"),t=window.localStorage.getItem("demo_lang");if("en"===e||"ja"===e){o(e),window.localStorage.setItem("demo_lang",e);return}("en"===t||"ja"===t)&&o(t)},[]),r.useEffect(()=>{document.documentElement.lang=s},[s]);let d=r.useCallback(e=>{o(e),window.localStorage.setItem("demo_lang",e)},[]),l=r.useMemo(()=>({lang:s,setLang:d,t:e=>i[s][e]}),[s,d]);return(0,a.jsx)(n.Provider,{value:l,children:t})}function d(){let e=r.useContext(n);if(!e)throw Error("useI18n must be used inside I18nProvider");return e}}}]);